import { cloneUploadFile } from '../chunk-X2ZYOJEA.js';

// src/steps/heic.ts
function jpegName(name) {
  if (/\.(heic|heif)$/i.test(name)) return name.replace(/\.(heic|heif)$/i, ".jpg");
  return `${name}.jpg`;
}
function heicStep() {
  return {
    name: "heic",
    shouldProcess: (file) => file.type === "image/heic" || file.type === "image/heif" || /\.(heic|heif)$/i.test(file.name),
    async process(file, _context) {
      try {
        const mod = await import('heic2any');
        const convert = mod.default;
        const result = await convert({
          blob: file,
          toType: "image/jpeg",
          quality: 0.92
        });
        const blob = Array.isArray(result) ? result[0] : result;
        if (!(blob instanceof Blob)) return file;
        const converted = new File([blob], jpegName(file.name), {
          type: "image/jpeg",
          lastModified: file.lastModified
        });
        return cloneUploadFile(file, converted, {
          originalSize: file.size,
          processedSize: converted.size,
          heicConverted: true
        });
      } catch {
        return file;
      }
    }
  };
}

export { heicStep };
